#include <stdio.h>
#include <math.h>
#define MOD 1000000007
int count(int n, int m, int d) {
    int count = m / d;
    return (int)pow(count, n);
}
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, m, l, r;
        scanf("%d %d %d %d", &n, &m, &l, &r);
        long long sum = 0;
        for (int d = l; d <= r; d++) {
            sum += count(n, m, d);
            sum %= MOD;
        }
        printf("%lld\n", sum);
    }
    return 0;
}

