import java.util.Scanner;
public class Main {
    static final int MOD = 1000000007;
    public static int count(int n, int m, int d) {
        int count = m / d;
        return (int) Math.pow(count, n);
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            int n = sc.nextInt();
            int m = sc.nextInt();
            int l = sc.nextInt();
            int r = sc.nextInt();
            long sum = 0;
            for (int d = l; d <= r; d++) {
                sum += count(n, m, d);
                sum %= MOD;
            }
            System.out.println(sum);
        }
    }
}

