def count(n, m, d):
    count = m // d
    return pow(count, n, MOD)
def main():
    t = int(sys.stdin.readline())
    for _ in range(t):
        n, m, l, r = map(int, sys.stdin.readline().split())
        sum = 0
        for d in range(l, r + 1):
            sum += count(n, m, d)
            sum %= MOD
        print(sum)
