const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let i = 0;
const MOD = 1000000007;
function count(n, m, d) {
    let count = Math.floor(m / d);
    let result = 1;
    for (let j = 0; j < n; j++) {
        result = (result * count) % MOD;
    }
    return result;
}
